"""
MKT Original Language Commentary — Isaiah chapters 1–4
Run: python3 scripts/zc-original-isaiah-1-4.py

Key decisions in this range:
- Isaiah 1 follows the rîb (lawsuit) pattern: summons (v2), charge (v3-15),
  call to return (v16-20), sentencing (v21-31); this legal structure shapes
  lexical choices throughout.
- ḥāzôn (v1:1) vs. dāḇār (v2:1): two distinct prophetic reception modes;
  Isaiah's self-description as visionary vs. hearer is significant.
- pāšaʿ (v1:2) is deliberate breach of covenant relationship, not mere error.
- ʾaḥărît hayyāmîm (v2:2) = "in the last days" — formula tied to
  eschatological expectation; not merely future but the decisive end-horizon.
- ṣemaḥ YHWH (v4:2) = "Branch of the LORD" — rare title; only here in Isaiah;
  paralleled in Jer 23:5, 33:15, Zech 3:8, 6:12 where it is explicitly Messianic.
- Style note: carry forward Isaiah's characteristic use of antithetic parallelism
  and catalog rhetoric (lists of judgment) from chapters 2-3.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
  "1": {
    "1": '<p><strong>ḥăzôn</strong> (<em>ḥāzôn</em>, H2377) — "vision/revelation received." Isaiah identifies his entire book as a single integrated vision, not a collection of separate oracles. This is the preferred self-description of classical Hebrew prophecy as direct visual perception rather than merely verbal reception. Compare Obadiah 1:1 and Nahum 1:1. The book of Isaiah opens with this rarer term rather than the more common <em>dāḇār</em> (word of the LORD), signaling that these oracles were experienced as a unified prophetic seeing.</p><p>The four-king span (Uzziah, Jotham, Ahaz, Hezekiah) dates the ministry to approximately 740–700 BCE — from the height of Judean prosperity through the Assyrian crisis. This temporal anchoring is not merely biographical; it situates the vision within the arc of covenant history.</p>',
    "2": '<p><strong>šimʿû šāmayim wĕhaʾăzînî ʾereṣ</strong> — "Hear, O heavens, and give ear, O earth." Two different Hebrew verbs: <em>šāmaʿ</em> (hear/obey) addressed to the heavens; <em>ʾāzan</em> (give ear/attend closely) to the earth. The distinction is stylistic but both are legal summons vocabulary. The cosmic witnesses (heavens and earth) are invoked as parties to the Sinaitic covenant (cf. Deut 30:19, 31:28; Mic 6:1-2), establishing the rîb (lawsuit) pattern that structures this entire chapter.</p><p><strong>pāšĕʿû</strong> (<em>pāšaʿ</em>, H6586) — not merely "sinned" or "erred" but deliberate, willful breach of a covenant relationship; rebellion of a vassal against a sovereign. The MKT renders "rebelled," which captures this active agency. The children (<em>bānîm</em>) whom YHWH reared to maturity (<em>giḏaltî</em>) have committed <em>pāšaʿ</em> — the most serious category of covenant violation.</p>',
    "3": '<p><strong>yādaʿ</strong> (H3045) — relational, experiential knowing, not merely cognitive recognition. "Israel does not know" means Israel has failed to maintain the covenant bond that constitutes relationship, not merely that Israel is ignorant of facts. An ox "knows" its owner in the sense of having an established bond of recognition and dependence.</p><p>The ox/donkey proverb is a <em>qal wahomer</em> (lesser-to-greater) argument: if even domesticated work animals maintain the primary bond of recognition with their owner, how much more should Israel, YHWH\'s covenant son, maintain theirs. <strong>ʾēbûs</strong> (H18) = "manger/feeding trough," not simply "master" — the donkey knows the source of its provision. Israel, by contrast, has stopped seeing YHWH as provider.</p>',
    "4": '<p><strong>hôy</strong> (H1945) — the exclamatory lament particle, used both as a funeral cry (alas!) and as a prophetic woe-oracle announcing judgment. Its combination with <em>gôy ḥōṭēʾ</em> (sinful nation) is striking: nations are never called "sinful" in Deuteronomic terms, only Israel — the one to whom covenant obligations applied. The entire verse has four accusatory phrases stacked asyndetically (without conjunctions), creating rhetorical urgency.</p><p><strong>ʿāzĕbû</strong> = "have abandoned" (perfect, completed action); <strong>nāʾăṣû</strong> = "have spurned" (perfect). Both verbs describe completed covenant breach, not ongoing drift. <strong>nāzōrû</strong> (H2114) = "are estranged, turned away" — the third charge. The accumulation reinforces the totality of the abandonment.</p>',
    "5": '<p><strong>ʿal-māh</strong> — "Why?" / "For what?" — the rhetorical question implies that further punishment is pointless, not that YHWH is incapable; Israel has reached the point of hardened incorrigibility. The entire body-politic metaphor of vv. 5-6 presupposes a patient who has refused all treatment.</p><p><strong>kol-rōʾš lāḥolî</strong> = "the whole head is sick/diseased (<em>ḥolî</em>)"; <strong>kol-lēḇāḇ dawwāy</strong> = "the whole heart is faint/failing (<em>dāwway</em>)." The pairing of head (leadership/mind) and heart (will/center) as both diseased signals comprehensive moral and social corruption from top to bottom.</p>',
    "6": '<p>The body metaphor from v. 5 is extended with clinical specificity: <strong>pĕṣaʿ</strong> = wound/laceration; <strong>ḥabbûrâ</strong> = bruise/welt; <strong>makkâ ṭĕriyyâ</strong> = open/fresh sore. All three denote different stages or types of injury, suggesting the comprehensive and untreated nature of the wound. Not merely injured but unattended.</p><p><strong>lōʾ-zōrû wĕlōʾ ḥubbāšû</strong> = "not pressed out, and not bound up" — wound treatment in ancient medicine involved squeezing out infected material, then bandaging. <strong>wĕlōʾ rukkeḵāh baššāmen</strong> = "and not softened with oil." All three remedial actions absent. The metaphor describes not the absence of suffering but the absence of any attempted cure.</p>',
    "7": '<p><strong>šĕmāmâ</strong> (H8077) — desolation, the word that names what is left after total devastation. Structurally related to the threat-language of Leviticus 26 and Deuteronomy 28 (covenant curses for covenant breach). Isaiah is describing the covenant curses coming to pass, not merely a political situation.</p><p><strong>kĕmaḥpēkat zārîm</strong> = "like the overthrow of strangers" — a disputed phrase; the MKT "a desolation like the ruin left by invaders" captures the comparison to devastation wrought by foreign armies. The land belongs to Israel but looks like it has been thoroughly colonized by outsiders.</p>',
    "8": '<p><strong>bat-ṣiyyôn</strong> — "daughter of Zion" — the city of Jerusalem personified as a daughter/young woman. This is a standard Hebrew personification idiom (cf. Lamentations 1-2). The emotional weight is grief for a beloved person, not just a place.</p><p><strong>sûkkâ</strong> = "temporary shelter/booth" — the agricultural harvest booth (related to the Feast of Booths, <em>sukkot</em>), flimsy and impermanent; <strong>mĕlûnâ</strong> = watchman\'s hut in a cucumber field — equally temporary. <strong>nĕṣûrâ</strong> = "besieged city." The three images move from vineyard to field to military siege — Jerusalem is isolated, exposed, temporary, as if already under attack.</p>',
    "9": '<p><strong>śārîd</strong> (H8300) = "survivor, remnant" — a crucial theological term in Isaiah (occurs repeatedly in chs. 1, 4, 6, 10, 11, 28, 37). The "tiny surviving remnant" (<em>kiṁʿāṭ</em> = "almost," with <em>śārîd</em>) is the sole basis for Israel\'s continued existence. Theologically: remnant is not a consolation prize but the seed of continuity.</p><p>The Sodom-Gomorrah comparison is jarring: those cities were the canonical example of total divine destruction (Gen 18-19). That Israel "would have been like Sodom" but for the remnant — not that Israel was like Sodom in wickedness, but in deserved fate — is a statement of sheer grace. The condition of survival is not merit but mercy.</p>',
    "10": '<p>The address to Jerusalem\'s leaders as "rulers of Sodom" (<em>qĕṣînê Sĕdôm</em>) and the people as "people of Gomorrah" is a rhetorical shock tactic — v. 9 had just said Israel was almost like Sodom in its destruction; now Isaiah says the leaders ARE Sodom-like in their character. The rîb lawsuit continues: <strong>šimʿû</strong> (hear, imperative) and <strong>haʾăzînû</strong> (give ear, imperative) repeat v. 2\'s legal summons, now directed at Judah\'s leadership specifically.</p>',
    "11": '<p><strong>māh-lî rōb-ziḇḥêkem</strong> — "What to me is the multitude of your sacrifices?" — rhetorical question dismissing the cult. <em>Māh-lî</em> = "what is it to me?" — a formula of total disinterest (cf. Matt 8:29). The verse does not condemn sacrifice per se but sacrifice divorced from obedience (cf. 1 Sam 15:22; Hos 6:6; Amos 5:21-24). This is the prophetic critique: the sacrificial system was never intended to substitute for covenant loyalty.</p><p><strong>śābaʿtî</strong> = "I am surfeited, I have had more than enough" (perfect of <em>śāḇaʿ</em>); <strong>lōʾ ḥāpaṣtî</strong> = "I do not desire/take pleasure in" (<em>ḥāpēṣ</em> = to delight in, take pleasure). YHWH\'s response to the temple cult is not theological interest but visceral revulsion — the strongest language of divine rejection.</p>',
    "12": '<p><strong>mî-biqēš zōʾt miyyĕdekem</strong> — "Who required this from your hands?" — <em>bāqaš</em> = to seek, require, demand. The question is devastating in its simplicity: no one asked for empty ritual. The rhetorical form implies the answer: YHWH himself did not require this; what he required was justice and righteousness (v. 17). The ritual came to substitute for what was actually demanded.</p><p><strong>rĕmōs ḥăṣērāy</strong> = "to trample through my courts" — the temple precincts (<em>ḥăṣēr</em>) are being polluted rather than honored by feet that bring no matching moral state. The image of trampling (used for enemy armies destroying cities in other contexts) applied to worshipers is deliberately provocative.</p>',
    "13": '<p><strong>lōʾ tôsîpû hāḇîʾ minḥat-šāwĕʾ</strong> — "Stop bringing worthless offerings." <em>Minḥat-šāwĕʾ</em> = "offering of emptiness/vanity" — <em>šāwĕʾ</em> (H7723) means nothingness, emptiness, falsehood (the same root as the third commandment: "take the name of the LORD in vain"). The offerings are themselves defined as <em>šāwĕʾ</em> because they are offered by those whose lives contradict them.</p><p><strong>qĕṭōret tôʿēḇâ</strong> = "incense is an abomination (<em>tôʿēḇâ</em>)" — <em>tôʿēḇâ</em> is the strongest ritual-disgust word in Hebrew, used for idolatry (Deut 7:25), sexual immorality (Lev 18:22), and unjust weights (Prov 11:1). Applying it to incense — prescribed in the law itself — is Isaiah\'s most radical statement: a commanded ritual can become an abomination when separated from covenant faithfulness.</p>',
    "14": '<p><strong>śānēʾtî</strong> (perfect of <em>śānēʾ</em>, to hate) — "I utterly hate." The perfective aspect emphasizes this as a settled state of divine disposition, not a momentary reaction. YHWH hates the festivals, new moons (<em>ḥodšêkem</em>), and appointments (<em>môʿădêkem</em>) — the full calendar of Levitically mandated gatherings. The word <em>môʿēd</em> (appointed time/festival) is the same word used in Leviticus 23 for the sacred calendar. The institutions are not condemned; their divorce from covenant life is.</p><p><strong>hāyû ʿālay lĕṭōraḥ</strong> = "they have become a burden to me" (<em>ṭōraḥ</em> = burden, travail). The image is ironic: Israel was supposed to be YHWH\'s treasured possession (<em>sĕgullâ</em>); instead the relationship has become a burden. <strong>nillêtî nĕśōʾ</strong> = "I am weary of carrying them" — the festivals have become a burden YHWH must sustain rather than an offering of worship.</p>',
    "15": '<p><strong>bĕpārĕśkem kappêkem</strong> — "when you spread out your palms/hands" — the gesture of supplication, hands extended outward and upward. <em>Kappayim</em> = palms (the hollow of the hand). The image is of the universal gesture of prayer — yet YHWH responds by hiding his eyes (<em>maʿlîm ʿênay</em> = "I will hide my eyes, avert my gaze").</p><p><strong>yĕdêkem dāmîm māĕʾû</strong> — "your hands are full of blood (<em>dāmîm</em>)." The plural <em>dāmîm</em> = bloodshed/bloodguilt (distinguished from <em>dām</em> = blood in general). The hands raised in prayer are the same hands covered in the blood of the innocent (social injustice, exploitation). This is the reason the prayers go unanswered: the posture of prayer and the posture of oppression cannot coexist.</p>',
    "16": '<p><strong>rāḥăṣû hizzakkû</strong> — "wash (<em>rāḥaṣ</em>) and make yourselves clean (<em>zāḵāh</em>)" — two imperatives, moving from external to internal: ritual washing and moral cleansing. <em>Rāḥaṣ</em> is the word for priestly ablutions; <em>zāḵāh</em> has broader moral-purity connotations. The sequence suggests that external ritual without internal transformation is the fundamental problem of vv. 11-15.</p><p><strong>sûrû rōaʿ maʿalĕlêkem</strong> — "remove (<em>sûr</em>) your evil deeds from before my eyes" — <em>sûr</em> = to turn aside, remove; the deeds must be actively removed, not merely regretted. The phrase <em>miggneged ʿênāy</em> = "from before my eyes" reverses v. 15 where YHWH hid his eyes from their prayers; now removal of evil results in restored divine attention.</p>',
    "17": '<p><strong>lĭmdû hêṭêb</strong> = "learn to do good" — the positive form of v. 16\'s negative commands. <em>Lāmad</em> (to learn) implies that doing good requires instruction and practice, not mere intention. <strong>dĭršû mišpāṭ</strong> = "seek/pursue justice" (<em>dāraš</em> = to seek with urgency, to investigate thoroughly). <strong>ʾaššĕrû ḥāmôṣ</strong> = "correct the oppressor" — a difficult phrase; <em>ʾāšar</em> can mean "to make straight/correct" and <em>ḥāmôṣ</em> = "oppressor/extortioner."</p><p><strong>šipṭû yātôm rîbû ʾalmānâ</strong> = "defend/judge the orphan, take up the widow\'s cause (<em>rîb</em>)." The <em>yātôm</em> (orphan) and <em>ʾalmānâ</em> (widow) are the canonical vulnerable pair in OT social law (Exod 22:22; Deut 10:18; 14:29; 24:17-21; Ps 68:5; 146:9). Their protection is the concrete test of covenant justice, not temple attendance.</p>',
    "18": '<p><strong>lĕkû-nāʾ wĕniwwākĕḥâ</strong> = "Come now and let us reason together/argue the case" — <em>yākaḥ</em> (H3198) is a legal-forensic term: to dispute a case, to bring a charge, to adjudicate. The divine invitation to "reason together" is a courtroom summons, not merely a friendly conversation. YHWH invites Israel to state their defense.</p><p><strong>yihyû kaššāleg yalbînû</strong> = "they shall become white as snow (<em>šeleg</em>)." <em>Šānî</em> and <em>tôlaʿat</em> (scarlet/crimson) = the red dye from the scale insect (<em>Kermes biblicus</em>) — a costly, deep, essentially permanent colorfast dye. Against this: <em>šeleg</em> (snow) and <em>ṣemer</em> (wool) = the paradigm of whiteness. The contrast of maximum color saturation against maximum whiteness makes this the most vivid forgiveness image in the OT.</p>',
    "19": '<p><strong>ʾim-tōʾbû wĕšĕmaʿtem</strong> = "if you are willing (<em>tōʾbû</em>, from <em>ʾābâ</em>, to be willing/agree) and obey (<em>šāmaʿ</em>, to hear/obey)." Both <em>ʾābâ</em> and <em>šāmaʿ</em> are volitional: the first is the inner disposition, the second the outward compliance. The condition is both attitude and action.</p><p><strong>ṭûb hāʾāreṣ tōʾkēlû</strong> = "the best/goodness of the land you shall eat." The blessing formula echoes Deuteronomy\'s prosperity language — the land as gift conditional on obedience (Deut 28:1-14). The obedience-blessing framework is operative throughout this pericope.</p>',
    "20": '<p><strong>ʾim-tĕmaʾănû wûmĕrîtem</strong> = "if you refuse (<em>māʾēn</em>) and resist (<em>mārar</em>)" — the two negatives matching the two positives of v. 19. <em>Māʾēn</em> = to refuse, decline (volitional); <em>mārar</em> = to be rebellious/bitter — the root of Miriam and Meribah.</p><p><strong>ḥereḇ tĕʾukkĕlû</strong> = "by the sword you shall be eaten/devoured" — the same verb <em>ʾākal</em> (eat) used in both the blessing (v. 19: you shall eat) and the curse (v. 20: you shall be eaten). The covenant structure of blessing and curse is embedded in the very grammar. <em>Pî YHWH dibbēr</em> = "for the mouth of the LORD has spoken" — the oracular confirmation formula that seals the pronouncement.</p>',
    "21": '<p><strong>ʾêkâh hāyĕtâ lĕzônâ</strong> = "How has she become a harlot (<em>zônâ</em>)!" — the lament particle <em>ʾêkâh</em> (alas/how) opens the dirge form (cf. Lamentations 1:1, 2:1, 4:1 — same word). The prophetic move from lawsuit to lament is abrupt and emotionally powerful. The city that was "faithful" (<em>neʾĕmānâ</em>) has become a <em>zônâ</em> — spiritual prostitution, covenant infidelity in its most degraded form.</p><p><strong>mišpāṭ/ṣedeq</strong> — the twin pillars of the ideal city: justice (right social order) and righteousness (conformity to divine standard). Their replacement by murderers (<em>mĕrṣāḥîm</em>) states the case with maximum compression: the city that was characterized by <em>mišpāṭ</em> and <em>ṣedeq</em> now has neither.</p>',
    "22": '<p><strong>kaspĕkā hāyâ lĕsîgîm</strong> = "your silver has become dross (<em>sîgîm</em>)." <em>Sîgîm</em> = slag, the waste product left after smelting — what is removed when refining silver, the opposite of the pure metal. The metaphor of metallurgical debasement (pure silver → dross; fine wine → diluted water) describes moral adulteration with precision: not ruined from outside but corrupted from within.</p><p><strong>sōbĕʾăkā māhûl bammāyim</strong> = "your finest wine (<em>sōbēʾ</em>) is diluted (<em>māhûl</em>) with water." <em>Māhûl</em> from the root <em>māhal</em> = to dilute, to adulterate. The pairing of adulterated silver and adulterated wine introduces the theme of the next verses: corrupt leaders who have debased justice as thoroughly as a merchant adulterates a product.</p>',
    "23": '<p><strong>šōrĕrîm</strong> = "rebels/revolters" — from <em>šārar</em> (to be hostile, to be an adversary); <strong>ḥaḇrê gaḇḇāʾîm</strong> = "companions of thieves (<em>gaḇ</em>)." The rulers are characterized not merely as corrupt but as partners in crime — their position as judges makes their complicity in theft the more damning.</p><p><strong>kullô ʾōhēḇ šōḥad</strong> = "every one loves a bribe (<em>šōḥad</em>)" — <em>šōḥad</em> is specifically the bribe that perverts legal judgment (cf. Deut 10:17; 16:19; Exod 23:8). <strong>wĕrōdēp šalmōnîm</strong> = "chasing after gifts/payoffs" (<em>šalmōnîm</em> = rewards/remunerations). The orphan (<em>yātôm</em>) and widow (<em>ʾalmānâ</em>) of v. 17 resurface: the same vulnerable groups YHWH commanded to protect are those the rulers actively fail.</p>',
    "24": '<p><strong>hāʾādôn YHWH ṣĕḇāʾôt ʾăḇîr yiśrāʾēl</strong> — three divine titles stacked: <em>hāʾādôn</em> (the Lord, sovereign), <em>YHWH ṣĕḇāʾôt</em> (LORD of armies/hosts), <em>ʾăḇîr yiśrāʾēl</em> (Mighty One/Champion of Israel — <em>ʾaḇîr</em> = bull/warrior). The threefold title makes this the most solemn divine pronouncement in the chapter; this is YHWH in his full covenant authority.</p><p><strong>ʾinnāḥēm</strong> (hithpael of <em>nāḥam</em>) = "I will relieve/console myself" — the reflexive form: YHWH relieves himself of the burden of his enemies (cf. v. 14: the festivals have been a burden). The word can also mean "comfort" (YHWH takes comfort in acting against evil) — the irony: the consolation that comes from punishing oppressors mirrors Israel\'s need for consolation.</p>',
    "25": '<p><strong>bōr</strong> (H1253) = lye, potash, a strong alkali used in ancient smelting to separate dross from metal. The refining metaphor returns (cf. v. 22: silver → dross): YHWH will apply <em>bōr</em> to Israel as a metallurgist refines silver, removing impurities (<em>sîgîm</em> = dross). The judgment is purposeful, not merely punitive — the goal is purification.</p><p><strong>wĕʾāsîrâ kol-ʾabddîlêk</strong> = "and I will remove all your alloy/impurities" — <em>bĕdîl</em> (H913) is specifically the tin or lead mixed into silver to create alloy; smelting removes it. The metaphor of smelting-as-judgment is pervasive in Hebrew prophecy (Jer 6:29; Ezek 22:18-22; Mal 3:2-3) and always implies a purified remnant on the other side of the furnace.</p>',
    "26": '<p><strong>wĕʾāšîḇâ šōpĕṭayik kĕḇārīʾšōnâ</strong> = "I will restore your judges as at the first" — the <em>kĕ-</em> (as/like) comparison points to the ideal period of Mosaic administration, not merely political stability. <em>Šāpaṭ</em> here points to the combined function of judge-deliverer (as in the book of Judges), not merely a juridical officer.</p><p><strong>qirěyat haṣṣedeq hāʾîr hanneʾĕmānâ</strong> — "the City of Righteousness (<em>ṣedeq</em>), the Faithful City (<em>neʾĕmānâ</em>)" — the terms of the ideal city in v. 21 (where she was called faithful) are fully restored. The judgment of vv. 24-25 is not termination but restoration: refining achieves what punishment could not — the city\'s original character.</p>',
    "27": '<p><strong>ṣiyyôn bĕmišpāṭ tiggāʾēl</strong> = "Zion will be redeemed through/by justice (<em>bĕmišpāṭ</em>)." The preposition <em>bĕ</em> here is instrumental: justice is the means of redemption, not merely its product. <em>Gāʾal</em> (H1350) = kinsman-redeemer action — the technical term for the near-kinsman who rescues family members from slavery, debt, or death (cf. Ruth 3-4; Lev 25). YHWH acting as kinsman-redeemer for Zion is one of Isaiah\'s major theological claims (cf. Isa 41:14; 43:14; 44:6; 47:4; 54:5).</p>',
    "28": '<p><strong>wĕšeber pōšĕʿîm wĕḥaṭṭāʾîm yaḥdāw</strong> = "and the crushing/breaking (<em>šeḇer</em>) of rebels and sinners together." <em>Pōšĕʿîm</em> (rebels, those who commit <em>pāšaʿ</em> — deliberate covenant breach, v. 2) and <em>ḥaṭṭāʾîm</em> (sinners, those who miss the mark). Both categories are destroyed together. <strong>wĕʿōzĕḇê YHWH yiklû</strong> = "and those who forsake the LORD will be consumed (<em>kālâ</em>)." The judgment is total for those in the second category; the remnant (v. 9) is for those who respond to the invitation of vv. 16-19.</p>',
    "29": '<p><strong>kî yēḇōšû mēʾêlîm ʾăšer ḥămaḏtem</strong> = "for you will be put to shame (<em>bôš</em>) because of the sacred oaks (<em>ʾêlîm</em>) you desired (<em>ḥāmad</em>)." <em>ʾÊlîm</em> (H352 + H356) are sacred oak trees used in Canaanite fertility cult worship (cf. Hos 4:13; Ezek 6:13). <em>ḥāmad</em> = to covet, desire intensely — the same root as the tenth commandment (do not covet). The desire for sacred trees is covenant-violation in the mode of coveting.</p><p><strong>gannôt</strong> = "ritual gardens" — gardens associated with fertility rites (cf. Isa 65:3; 66:17). The shame (<em>bôš</em>) will be commensurate with the desire: the things Israel pursued will become the occasion of their disgrace.</p>',
    "30": '<p><strong>kĕʾallâ nōḇelet ʿălêhā</strong> = "like an oak tree with falling/withering leaves (<em>nōḇelet</em>)" — <em>nāḇal</em> = to wilt, fade, fall (related to the word for corpse, the foolish person, and the wineskin that deflates). The sacred oak (<em>ʾêlâ</em> = terebinth/oak, v. 29) becomes the image of Israel\'s own fate — the tree they worshipped becomes the metaphor for their withering.</p><p><strong>wĕkĕgannâ ʾăšer mayim ʾên lāh</strong> = "like a garden without water" — the ritual gardens of v. 29 now lack the water that gives life. The irony: Israel pursued fertility cult practices at watered sacred groves; their judgment is to become a waterless garden. The judgment mirrors the sin precisely.</p>',
    "31": '<p><strong>wĕhāyâ heḥāsôn lĕniṣôreṯ</strong> = "and the powerful one (<em>ḥāsôn</em>) will become tinder (<em>niṣôreṯ</em>)" — <em>ḥāsôn</em> (H2626) = strong, powerful; <em>niṣôreṯ</em> (H5369 or H5534) = tinder, something that easily catches fire. The most powerful person becomes the most combustible — power without covenant alignment becomes fuel for judgment.</p><p><strong>û-pōʿălô lĕniṣôṣ</strong> = "and his work (<em>pōʿal</em>) a spark (<em>niṣôṣ</em>)." The person and their deeds burn together simultaneously. <strong>wĕšārĕpû šĕnêhem yaḥdāw wĕʾên mĕkaббeh</strong> = "and both will burn together with no one to put them out" — the self-consuming judgment: the oppressor and his works destroy each other.</p>'
  },
  "2": {
    "1": '<p><strong>haddāḇār ʾăšer ḥāzâ</strong> = "the word (<em>dāḇār</em>) that Isaiah... saw (<em>ḥāzâ</em>)" — the syntax of this superscription is noteworthy. Here <em>dāḇār</em> (word) replaces the <em>ḥāzôn</em> (vision) of 1:1, but the verb is still <em>ḥāzâ</em> (to see/behold). Isaiah "sees" a word — the word is something that can be visually perceived, not merely heard. This is distinct from other prophetic books that use <em>ḥāyâ dĕḇar YHWH ʾel-</em> ("the word of the LORD came to"), suggesting a different mode of reception for this oracle.</p>',
    "2": '<p><strong>bĕʾaḥărît hayyāmîm</strong> = "in the last days/at the end of days" — a fixed eschatological formula in Hebrew prophecy (Gen 49:1; Num 24:14; Deut 4:30; 31:29; Hos 3:5; Mic 4:1; Dan 2:28). This is not just "in the future" but a terminus — the decisive end-horizon toward which history is moving. The formula grounds the oracle in a different temporal register from the oracles of judgment in ch. 1.</p><p><strong>nākôn yihyeh har-bêt YHWH</strong> = "the mountain of the house of the LORD will be established (<em>nākôn</em>, niphal of <em>kûn</em>)" — <em>kûn</em> (H3559) = to be fixed, established, prepared; the niphal passive means "will be firmly established/prepared." The mountain of YHWH\'s house is presently one mountain among many; it will be established as supreme — a complete inversion of current political geography. This oracle is verbatim repeated in Mic 4:1-3.</p>',
    "3": '<p><strong>yōrēnû miḏḏĕrākāyw</strong> = "he will instruct us in his ways" — <em>yārâ</em> (H3384) = to throw, shoot; in the hiphil, to direct, point, instruct; the noun <em>tôrâ</em> (teaching/law) derives from this root. The nations actively seek to be taught YHWH\'s <em>tôrâ</em> — the instruction that flows outward from Zion is not imposed by conquest but sought by willing learners.</p><p><strong>kî miṣṣiyyôn tēṣēʾ tôrâ ûḏĕḇar YHWH mîrûšālāim</strong> = "for out of Zion will go forth Torah, and the word of the LORD from Jerusalem." The centripetal movement of v. 2 (nations flowing to Zion) reverses in v. 3 to centrifugal: <em>tôrâ</em> and <em>dĕḇar YHWH</em> going out from Zion to the nations. Both directions of movement are eschatological — not present reality but end-time promise.</p>',
    "4": '<p><strong>wĕšāpaṭ bên haggôyim</strong> = "and he will judge/arbitrate between the nations" — <em>šāpaṭ</em> here is judicial arbitration, not punitive condemnation. YHWH as universal judge settles disputes between nations, eliminating the need for warfare as a dispute-resolution mechanism.</p><p><strong>wĕkitĕtû ḥarĕḇôtām lĕʾittôt ûḥănîtôtêhem lĕmazĕmērôt</strong> = "they will beat their swords (<em>ḥereb</em>) into plowshares (<em>ʾēt</em>) and their spears (<em>ḥănît</em>) into pruning hooks (<em>mazmērâ</em>)" — the versal pivot of the oracle. <em>Kātat</em> (to beat/pound) is the verb of metalworking — swords are hammered into agricultural tools, weapons into instruments of harvest. The reversal in Joel 3:10 (pruning hooks into spears) shows the motif can be read in either direction depending on the oracle.</p>',
    "5": '<p><strong>bêt yaʿăqōb lĕkû wĕnēlĕkâ bĕʾôr YHWH</strong> = "O house of Jacob, come, let us walk in the light of the LORD." Following the vision of eschatological peace (vv. 2-4), Isaiah turns to a present exhortation. <em>Bêt yaʿăqōb</em> here = the covenant people as a whole. The call to "walk (<em>hālaḵ</em>) in the light (<em>ʾôr</em>) of the LORD" is the present-tense response to the eschatological promise: the nations will come to Zion\'s light in the future; Jacob should be walking in it now.</p>',
    "6": '<p><strong>kî nāṭaštā ʿamĕkā bêt yaʿăqōb</strong> = "for you have rejected (<em>nāṭaš</em>) your people, the house of Jacob" — <em>nāṭaš</em> (H5203) = to forsake, abandon, leave alone. The conjunction <em>kî</em> (for/because) grounds the call of v. 5 in the present reality: Israel is currently in a state of divine abandonment — the reason they need to be called back to YHWH\'s light.</p><p><strong>miqqedem</strong> = "from the east" — specifically Eastern divinatory practices. <strong>qōsĕmîm</strong> = diviners/practitioners of divination (H7080, <em>qāsam</em>). <strong>yišpĕqû bĕyaldê nŏḵrîm</strong> = "and they clasp hands with the children of foreigners" — striking hands as a gesture of covenant or agreement (cf. Prov 11:21; 17:18); commercial or treaty alliances with foreign nations that involved adopting their religious practices.</p>',
    "7": '<p><strong>wattimmālēʾ ʾarṣô keseṕ wĕzāḥāḇ</strong> — "and his land was filled with silver and gold" — the three-fold <em>wattimmālēʾ</em> (was filled) structure of vv. 7-8 is a rhetorical indictment: land filled with treasures → land filled with horses → land filled with idols. Each filling is a violation of Deuteronomic kingship law (Deut 17:16-17: the king must not multiply horses, wives, or gold). Isaiah describes a nation that has done all three.</p><p><strong>ûmišsûsāyw</strong> = "and their horses" — horses were associated specifically with Egyptian military power (Deut 17:16 prohibits the king from returning to Egypt to multiply horses). Israel\'s military trust has migrated from YHWH to cavalry.</p>',
    "8": '<p><strong>wattimmālēʾ ʾarṣô ʾĕlîlîm</strong> = "and his land was filled with idols (<em>ʾĕlîlîm</em>)" — <em>ʾĕlîlîm</em> (H457) is a derogatory diminutive from <em>ʾēl</em> (god): "nothings/worthless ones/non-gods." The term appears specifically in prophetic polemic and the psalms as a dismissal of idols as non-entities (cf. Ps 96:5).</p><p><strong>lĕmaʿăśēh yādāyw yištaḥăwû</strong> = "they bow down to the work of their hands (<em>maʿăśēh yādāyw</em>)" — the manufacture-then-worship sequence is the central absurdity of idol polemic in Isaiah (developed more fully in Isa 44:9-20). The creator and the creation have been inverted: the maker worships what he made.</p>',
    "9": '<p><strong>wayyiššaḥ ʾādām wayyišpal ʾîš</strong> = "Mankind is bowed down and every person humbled" — <em>šāḥâ</em> and <em>šāpēl</em> are the two verbs of humiliation that run through ch. 2 as a refrain (vv. 11, 17). Here they describe human idolaters prostrating themselves; the irony is that the posture of idolatry is also the posture of divine judgment — those who bow to idols will be "brought low" by YHWH.</p><p><strong>wĕʾal-tiśśāʾ lāhem</strong> = "do not lift them up/forgive them!" — the negative command addressed to YHWH (or to the prophet?). This is a petition against divine forgiveness, asking that the judgment not be stayed. The severity of idolatry (covenant violation at its most basic) is such that mercy itself is inappropriate.</p>',
    "10": '<p><strong>bôʾ baṣṣûr wĕhiṭṭāmēn bɛʿāpār</strong> = "Enter the rocks (<em>ṣûr</em>) and hide in the dust (<em>ʿāpār</em>)" — the two imperatives of terrified flight. <em>ʿāpār</em> (dust) recalls Gen 3:19 (return to the dust in death) — the flight into rock and dust is a death-impulse, a wish to become inanimate before the divine presence. The imagery is extended in Rev 6:15-17 (kings and great men hiding in rocks and mountains from the wrath of the Lamb).</p><p><strong>mippenê paḥad YHWH ûmehādar gĕʾônô</strong> = "from before the terror (<em>paḥad</em>) of the LORD and the splendor (<em>hāḏār</em>) of his majesty (<em>gĕʾônô</em>)" — three weighty nouns: <em>paḥad</em> = dread/terror; <em>hāḏār</em> = glory/splendor/beauty; <em>gĕʾôn</em> = majesty/pride (when used of YHWH, always positive: the divine magnificence that reduces human pride to nothing). The refrain in vv. 10, 19, 21 marks the three movements of the oracle.</p>',
    "11": '<p><strong>ʿênê gaḇhût hāʾādām tišpālenāh</strong> = "the proud eyes (<em>ʿênê gaḇhût</em>) of mankind will be brought low (<em>šāpēl</em>)" — <em>gaḇhût</em> = height, altitude, pride; the "high eyes" are the haughty gaze that does not look up to YHWH but only across at peers. <em>šāpēl</em> (hiphil: to make low) is the verbal form of the great eschatological leveling.</p><p><strong>wĕnišgāḇ YHWH lĕḇaddô bayyôm hahûʾ</strong> = "and the LORD alone will be exalted (<em>nišgāḇ</em>, niphal of <em>śāḡaḇ</em>) in that day." <em>Śāḡaḇ</em> = to be high, inaccessibly elevated. YHWH being "alone (<em>lĕḇaddô</em>) exalted" is the theological core of the oracle: the Day of the LORD is the day when no human or made thing shares YHWH\'s elevation.</p>',
    "12": '<p><strong>kî yôm lĕYHWH ṣĕḇāʾôt ʿal kol-gāʾeh wĕrām</strong> = "for a day belongs to the LORD of hosts against everything proud and lofty." The "Day of the LORD" is not specified by timing but by character: it is YHWH\'s day of active assertion against everything that has usurped his position. <em>Gāʾeh</em> = proud/haughty (H1343); <em>rām</em> = exalted/lifted up (H7311). The language echoes Isaiah\'s commissioning vision (6:1 — "I saw the Lord... high and lofted up (<em>rām wĕniśśāʾ</em>)") — only YHWH is to be <em>rām</em>.</p>',
    "13": '<p><strong>ʿal kol-ʾarzê hallĕḇānôn hārāmîm wĕhanniśśāʾîm</strong> = "against all the cedars of Lebanon, lofty (<em>hārāmîm</em>) and lifted up (<em>wĕhanniśśāʾîm</em>)" — the two adjectives applied to the cedars are the vocabulary of divine elevation in 6:1 ("high and lifted up"). The trees that grow tallest and are most admired symbolize human pride at its most impressive. Cedars of Lebanon were the royal building material par excellence (Solomon\'s temple, Hiram\'s timber).</p><p><strong>wĕʿal kol-ʾallônê habbāšān</strong> = "and all the oaks of Bashan" — Bashan (east of the Jordan, modern Golan) was famous for its oaks and fat cattle. Both Lebanon\'s cedars and Bashan\'s oaks = the tallest, most imposing trees of the ancient Near East.</p>',
    "14": '<p><strong>wĕʿal kol-heheHārîm hārāmîm</strong> = "against all the high mountains" — shifting from trees to topography. The catalog of things brought low in vv. 13-16 moves from natural wonders (trees, mountains, hills) to human constructions (towers, walls, ships). Both creation and civilization are subjected to the divine leveling. Mountains and hills were also the sites of Canaanite high places and foreign cults (cf. 1:29).</p>',
    "15": '<p><strong>wĕʿal kol-migdāl gābōhâ wĕʿal kol-ḥômâ bĕṣûrâ</strong> = "against every high tower (<em>migdāl</em>) and every fortified wall (<em>ḥômâ bĕṣûrâ</em>)" — the transition from natural features to military architecture. The tower (cf. the tower of Babel, Gen 11:4) and the fortified wall represent human military confidence — the trust in defensive engineering rather than in YHWH. These are the objects of both national pride and security planning.</p>',
    "16": '<p><strong>wĕʿal kol-ʾoniyyôt taršîš</strong> = "against all the ships of Tarshish" — Tarshish was the farthest-known western destination (Spain? Sardinia?), associated with long-distance merchant trade and great wealth. The "ships of Tarshish" became a symbol for commercial power and luxury (1 Kgs 10:22; Ps 48:7; Ezek 27:25). <strong>ʿal kol-haśśĕkiyyôt haḥemdâ</strong> = "against all their desirable craft/vessels" — <em>śĕkiyyôt</em> (H7914) is rare; context suggests prized or coveted items (NJPS: "lovely craft"). The catalog ends with luxury commerce — the ultimate symbol of wealthy self-sufficiency.</p>',
    "17": '<p>The refrain of v. 11 is repeated verbatim, creating a rhetorical inclusio around the catalog of vv. 12-16: <strong>wĕšāḥ gĕbah hāʾādām</strong> and <strong>wĕnišgāḇ YHWH lĕḇaddô</strong>. The repetition is not redundancy but structural emphasis — the catalog of proud things (trees, mountains, towers, ships) is bracketed by the declaration of their humbling. Whatever is proudly elevated will be brought to the same level; YHWH alone will remain elevated.</p>',
    "18": '<p><strong>wĕhāʾĕlîlîm kālîl yăḥălōp</strong> = "and the idols (<em>ʾĕlîlîm</em>) will completely (<em>kālîl</em>) vanish/pass away (<em>ḥālaph</em>)" — <em>kālîl</em> = wholly, completely (used elsewhere of whole burnt offerings); <em>ḥālaph</em> = to pass away, disappear, change. The terse sentence (four Hebrew words) is almost contemptuous in its brevity: the idols that dominate the land of v. 8 will simply disappear entirely. No battle, no polemic — they vanish.</p>',
    "19": '<p>The refrain of v. 10 expands here with new imagery: <strong>bimĕʿārôt ṣûrîm ûbimḥillôt ʿāpār</strong> = "into the caves of the rocks and into the holes of the dust/ground." The flight intensifies: v. 10 spoke of entering rocks and hiding in dust; v. 19 adds caves and underground holes — deeper concealment, greater terror. This is the cosmic-panic reversal of Amos 9:2-3 (where even hiding in the depths or under Carmel does not escape YHWH).</p>',
    "20": '<p><strong>bayyôm hahûʾ yašlîḵ hāʾādām ʾēt ʾĕlîlê kasppô wĕʾēt ʾĕlîlê zĕhāḇô</strong> = "In that day people will throw away (<em>šālaḵ</em>, to hurl/cast away) their silver idols and gold idols" — the same sequence as ch. 2\'s indictment (v. 7: silver and gold; v. 8: idols). In the day of divine terror, people abandon the very idols they made at great expense. <em>ʾĕlîlê</em> (worthless things) made of precious metals: the elaborate worthlessness of the idol is exactly proportional to the cost of its materials.</p><p><strong>laḥpōr pêrôt wĕlāʿaṭallēp̄îm</strong> = "to the moles and the bats" — burrowing animals that live in darkness and underground spaces. The precious idols are thrown to creatures that live in the very places humans will be hiding. The silver and gold that gave the idols their grandeur are now discarded in the flight into darkness.</p>',
    "21": '<p>A third and final refrain of the hiding-in-rocks motif, with fuller elaboration: <strong>bĕniqrôt haṣṣûrîm ûbĕsĕʿîpê hassĕlāʿîm</strong> = "in the clefts of the rocky crags and in the fissures of the cliffs." The vocabulary escalates — more specific terms for rock formations, deeper concealment. The threefold repetition (vv. 10, 19, 21) mimics the rhythm of an eschatological drumbeat: again and again the same flight, the same terror, the same sovereign.</p>',
    "22": '<p><strong>ḥidlû lākem min-hāʾādām ʾăšer nĕšāmâ bĕʾappô</strong> = "Stop trusting in mere mortals who have only a breath (<em>nĕšāmâ</em>) in their nostrils" — the chapter\'s practical conclusion. <em>ḥāḏal</em> (H2308) = to cease, stop, desist from. The breath in the nostrils recalls Gen 2:7 (<em>nišmat ḥayyîm</em> = breath of life breathed into Adam\'s nostrils) — it is the most contingent aspect of human existence, the most easily extinguished. <em>Bammeh neʾĕśab-hûʾ</em> = "what account is he really worth?" (<em>neʾĕśab</em> from <em>ḥāšaḇ</em> = to reckon, account). The rhetorical question demands the answer: nothing, measured against the divine majesty that has just been described.</p>'
  },
  "3": {
    "1": '<p><strong>hāʾādôn YHWH ṣĕḇāʾôt</strong> = "the Lord (<em>hāʾādôn</em>), the LORD of hosts" — two distinct divine titles. <em>Hāʾādôn</em> (with definite article) emphasizes absolute sovereignty; <em>YHWH ṣĕḇāʾôt</em> = LORD of armies/heavenly hosts. The combination heightens the authority of the following announcement.</p><p><strong>mašʿēn ûmašʿēnâ</strong> = "support (<em>mašʿēn</em>, masc.) and staff (<em>mašʿēnâ</em>, fem.)" — two forms of the same root (from <em>šāʿan</em>, to lean upon), one masculine, one feminine, creating a comprehensive "all supports" through gender variation. The double word means every kind of thing that can be relied upon. YHWH is removing from Jerusalem every prop on which the city leans — both physical (bread and water, v. 1b) and social (the leadership catalog of vv. 2-3).</p>',
    "2": '<p>The removal catalog begins: <strong>gibbôr</strong> = warrior/mighty man; <strong>ʾîš milḥāmâ</strong> = man of war (military professional); <strong>šōpēṭ</strong> = judge; <strong>nāḇî</strong> = prophet; <strong>qōsēm</strong> = diviner (included here alongside legitimate leaders — the catalog is sociological rather than theological; all leadership types disappear); <strong>zāqēn</strong> = elder. The list spans political, military, judicial, prophetic, and divinatory leadership — the entire social structure that holds a city together.</p>',
    "3": '<p>The catalog continues: <strong>śar-ḥămiššîm</strong> = "captain of fifty" — a military rank (cf. 2 Kgs 1:9-15); <strong>nĕśûʾ pānîm</strong> = "man of standing/person of distinction" (lit. "one whose face is lifted up" — someone with honor and social status); <strong>yôʿēṣ</strong> = counselor/advisor; <strong>ḥăkam ḥărāšîm</strong> = "skilled artisan/master craftsman" (<em>ḥāraš</em> = craftsman, especially metalworker or woodworker); <strong>nĕḇôn laḥaš</strong> = "expert in charms/enchantments" (<em>lāḥaš</em> = whispered charm, serpent charming). The inclusion of craftsmen and enchanters alongside military captains shows the comprehensive social disintegration: even technical and magical expertise disappears.</p>',
    "4": '<p><strong>wĕnātattî nĕʿārîm śārêhem</strong> = "I will make youths (<em>nĕʿārîm</em>) their rulers" — <em>nāʿar</em> = youth, boy (often with connotations of inexperience, rashness, or servile status). The word that in other contexts describes Joseph as a young servant (Gen 39:2) or Rehoboam\'s bad counselors (1 Kgs 12:8-11) now names the rulers of Jerusalem. The reversal of age and wisdom hierarchies is the judgment.</p><p><strong>ûtaʿălûlîm yimšĕlû-ḇām</strong> = "and infants/capricious ones will govern them" — <em>taʿălûl</em> (H8586) is rare and disputed: "infants" (NIV/ESV), "capricious ones" (NJPS), "babes" (KJV). The root <em>ʿālaʿ</em> suggests wantonness or playful caprice. Either way: the city that once had Solomonic wisdom will be governed by those who have neither age nor discernment.</p>',
    "5": '<p><strong>wĕniggaś hāʿam ʾîš bĕʾîš</strong> = "The people will oppress each other, man against man" — the social contract collapses from horizontal solidarity into mutual exploitation. <em>Nāgaś</em> (H5065) = to press, drive, exacte (the same word used for Egyptian slave-drivers in Exod 3:7; 5:6). Every member of the community becomes a slave-driver to every other.</p><p><strong>wĕhazzāqēn</strong> = "and the elder" — the reversal of the age hierarchy from v. 4 is now stated socially: youth is "arrogant against (<em>yirgĕzôz</em>)" the elder; the base (<em>niqaleh</em>, from <em>qālal</em> = to be light, contemptible) against the honorable (<em>nikkābēd</em>, from <em>kāḇēḏ</em> = heavy/weighty/honored). These are the honor-shame categories of the ancient world: <em>kāḇēḏ</em> (weighty) = honorable; <em>qālal</em> (light) = contemptible. Social disintegration is expressed through the inversion of these categories.</p>',
    "6": '<p><strong>kî-yiṯpōś ʾîš bĕʾāḥîw</strong> = "for a man will seize his own brother" — the seizure (<em>tāpas</em> = to grasp, catch) is coercive: grabbing an unwilling person for forced leadership. The desperation of the scenario: even the brother is the one seized, pointing to the complete breakdown of family solidarity as a social resource.</p><p><strong>śalmâ lĕkā qāṣîn tihyeh-lānû</strong> = "you have a robe (<em>śalmâ</em>), be our leader/ruler (<em>qāṣîn</em>)!" The only qualification offered for leadership is possession of a garment — the minimum visible marker of social standing above the desperately poor. The depletion of all other social resources has made a robe sufficient credential for authority.</p>',
    "7": '<p><strong>yiśśāʾ bayyôm hahûʾ lēʾmōr</strong> = "he will protest on that day, saying" — the <em>naśāʾ qôl</em> (lifting of the voice) is a formal response to the seizure of v. 6. The refusal of leadership is not cowardice but honest assessment: the designated leader has nothing to give.</p><p><strong>lōʾ-ʾehyeh ḥōḇēš</strong> = "I am no healer/binder of wounds" — <em>ḥōḇēš</em> from <em>ḥāḇaš</em> = to bind up wounds (used in Isa 1:6; also Ezek 30:21). The word connects back to ch. 1\'s body-politic metaphor: the city\'s wounds are unbound (1:6), and now no one is willing to be the wound-binder. The social disintegration of ch. 3 is the direct consequence of the moral disintegration of ch. 1.</p>',
    "8": '<p><strong>kî kāšĕlâ yĕrûšālāim wîhûḏâ nāpāl</strong> = "for Jerusalem has stumbled (<em>kāšal</em>) and Judah has fallen (<em>nāpal</em>)" — the two verbs describe stages of collapse: stumbling (destabilization) followed by falling (collapse). Jerusalem precedes Judah (the capital before the province) — the failure begins at the center and extends outward.</p><p><strong>lĕšônām wĕmaʿalĕlêhem ʾel-YHWH</strong> = "their tongue (<em>lāšôn</em>) and their deeds (<em>maʿălāl</em>) against the LORD" — both speech and action are directed against YHWH. <strong>lĕmārôt ʿênê kĕḇôdô</strong> = "defying/provoking (<em>mārar</em>) the eyes of his glory (<em>kāḇôd</em>)" — the divine <em>kāḇôd</em> (glory) is not merely abstract honor but a visual presence (Isa 6:3); defying "the eyes of his glory" means acting as if YHWH does not see and is not present.</p>',
    "9": '<p><strong>hakarāt pĕnêhem ʿānĕtâ bām</strong> = "the expression (<em>hakārat</em>) of their faces has testified against them" — <em>hakkārāh</em> = recognition, appearance; what the face reveals about the person. The moral state of Jerusalem is so manifest that the faces of its people are self-indicting testimony. They do not need to be charged — they accuse themselves.</p><p><strong>wĕḥaṭṭāʾtām kĕsĕdôm higgîdû lōʾ kiḥēdû</strong> = "they parade (<em>higgîd</em>) their sin like Sodom and do not conceal (<em>kāḥad</em>) it." The Sodom comparison recurs from 1:9-10, but here the charge is specific: deliberate, shameless public display of what Sodom did. The sin is not hidden but flaunted — the opposite of the shame that might lead to repentance.</p>',
    "10": '<p><strong>ʾimrû ṣaddîq kî-ṭôḇ</strong> = "Say of the righteous that it will go well (<em>ṭôḇ</em>) for him" — the call to proclaim good news to the righteous is a counter-note within the judgment oracle. Even in the midst of social chaos (vv. 1-9), there is a word for the righteous: they will eat the fruit of their actions. <em>Kî pĕrî maʿalĕlêhem yōʾkēlû</em> = "for the fruit of their deeds (<em>maʿălāl</em>) they will eat." The same <em>maʿălāl</em> (deeds) used pejoratively in vv. 8 serves here positively: righteous deeds produce righteous fruit.</p>',
    "11": '<p><strong>ʾôy lĕrāšāʿ rāʿ</strong> = "Woe to the wicked — it will go badly (<em>rāʿ</em>)" — the second <em>ôy</em> (woe) in the book (cf. 1:4). The lex talionis principle stated: <em>kîggĕmûl yādāyw yēʿāśeh-llô</em> = "for what his hands have done will be done to him in return." <em>Gāmal</em> = to deal out, recompense; the reflexive return of deed to doer. This is the principle underlying both OT and NT eschatology — deeds return to their originator.</p>',
    "12": '<p><strong>ʿammî nōgĕśāyw mĕʿôlēl</strong> = "My people — their oppressors are children (<em>mĕʿôlēl</em>)" — <em>mĕʿôlēl</em> is disputed: "infants/children" (LXX) or "those who treat them like children" (i.e., capriciously). The connection to v. 4 (<em>nĕʿārîm</em> and <em>taʿălûlîm</em>) suggests "children" is correct — the judgment of immature rulers is now being experienced.</p><p><strong>wĕnāšîm māšĕlû-ḇô</strong> = "and women rule over them" — read within its ANE context, not modern: female rule was the cultural marker of a society whose men had been killed, exiled, or disempowered. The point is the inversion of expected leadership structures, not a critique of women per se. <strong>mĕʾaššĕrêkā maṭʿîm</strong> = "your guides lead you astray" (lit. "those who call you blessed cause you to err") — the very people who provide reassurance are those leading into error.</p>',
    "13": '<p><strong>niṣṣāḇ lārîḇ YHWH wĕʿōmēd lādîn ʿammîm</strong> = "the LORD has taken his stand (<em>niṣṣāḇ</em>, niphal of <em>yāṣaḇ</em>) to bring a charge (<em>rîb</em>) and stands (<em>ʿōmēd</em>) to judge (<em>dîn</em>) peoples." The rîb (lawsuit) pattern from ch. 1 is explicitly invoked: YHWH as both prosecutor and judge. The prophetic perfect (niphal of <em>yāṣaḇ</em>) treats the future judicial action as already accomplished in its certainty.</p>',
    "14": '<p><strong>bĕziqnê ʿammô ûśārāyw yāḇôʾ bamišpāṭ</strong> = "He will enter into judgment (<em>mišpāṭ</em>) with the elders and rulers (<em>śārîm</em>) of his people" — specifically the leaders of Israel are the defendants, not nations in general. The charge against them: <strong>wĕʾattem biʿartĕm hakkārem</strong> = "you have plundered/burned (<em>bāʿar</em>) the vineyard." <em>Hakkārem</em> = "the vineyard" — the vineyard that is Israel (cf. 5:1-7, where the vineyard imagery is developed into a full allegory). The leaders have burned/pillaged what was entrusted to them.</p>',
    "15": '<p><strong>mallĕkem tedakkĕʾû ʿammî</strong> = "What do you think you are doing, crushing (<em>dākaʾ</em>) my people?" — <em>dākaʾ</em> = to crush, grind to powder (used for grinding grain; also of the crushed Servant in Isa 53:5). The same verb will describe the Servant who is crushed for our sins. Here it describes what the leaders are doing to the people. <strong>ûpĕnê ʿăniyyîm tiṭḥānû</strong> = "and grinding the faces of the poor into the dust" — the milling metaphor: the poor are grain being ground under the millstone of economic and judicial exploitation.</p>',
    "16": '<p><strong>bĕnôt ṣiyyôn</strong> = "daughters of Zion" — the women of Jerusalem, addressed in contrast to the bat-tsion of 1:8 (which is the city personified). Here the daughters are the elite women who have absorbed the city\'s values. <strong>bĕgābah ʿênayim</strong> = "with haughty/lifted eyes" — <em>gāḇah</em> in eyes = arrogance (cf. 2:11); <strong>ûbĕṭāpheph tēlakhnâ</strong> = "and prancing/tripping (<em>ṭāpheph</em>) as they walk" — the verb imitates mincing steps; <strong>ûbĕraglêhem tĕʿakkasênāh</strong> = "and jingling with their feet (<em>ʿākaś</em>)" — ankle bracelets that make a sound as they walk, advertising their presence and wealth.</p>',
    "17": '<p><strong>wĕšippaḥ ʾăḏōnāy qodqod bĕnôt ṣiyyôn</strong> = "the Lord will afflict the scalps (<em>qodqod</em>) of the daughters of Zion with sores" — <em>šippaḥ</em> = to lay bare, to make scabby; <em>qodqod</em> = the crown of the head, the top. The proud head (v. 16: lifted eyes, styled hair) is specifically targeted. <strong>YHWH pitĕhen yĕʿāreh</strong> = "the LORD will expose their nakedness/shame (<em>pōt</em>)" — the revelation of nakedness is the ultimate reversal of the elaborate covering described in vv. 18-23.</p>',
    "18": '<p>The catalog of ornaments removed in vv. 18-23 is the most detailed inventory of women\'s jewelry and clothing in the OT. Its comprehensiveness mirrors the comprehensiveness of the social catalog in vv. 2-3: just as every form of leadership is removed (vv. 2-3), every form of adornment is removed here. The parallel structure suggests the ornaments are a form of social-power display, not merely personal decoration.</p><p><strong>ʿăkāsîm</strong> = anklets (cf. v. 16); <strong>šĕbîsîm</strong> = headbands/hairnets; <strong>haśśahărōnîm</strong> = crescent ornaments/moon-shaped pendants (from <em>sahăr</em> = moon; possibly related to moon-cult jewelry).</p>',
    "19": '<p>Continuing: <strong>hannĕṭîpôt</strong> = eardrops/pendants (from <em>nāṭap̄</em> = to drip/hang); <strong>haššĕʾērôt</strong> = bracelets or chains (disputed: "chains" NIV; "bangles" ESV; from root meaning threaded items?); <strong>hārĕʿālôt</strong> = veils (of a fine, thin material — cf. Song 5:7).</p>',
    "20": '<p><strong>happĕʾērîm</strong> = turbans/headdresses (<em>pĕʾēr</em> = ornament, glorify; cf. Isa 61:3 where YHWH gives the "crown of beauty" as a messianic gift — here it is removed); <strong>haṣṣĕʿādôt</strong> = armlets/ankle chains; <strong>haqqiššurîm</strong> = sashes/cinctures; <strong>bāttê hanneppeš</strong> = "houses of breath" = perfume bottles (lit. "houses of the soul/breath" — containers that hold aromatic spirits); <strong>haḥăḇāšîm</strong> = lucky charms/amulets (lit. "binding items").</p>',
    "21": '<p><strong>haṭṭabbāʿôt</strong> = signet rings (<em>ṭabbāʿat</em> from <em>ṭāḇaʿ</em> = to dip/seal); signet rings bore the family insignia and were used to seal documents and transactions — both jewelry and instruments of social power and legal identity; <strong>nizmê hāʾāp̄</strong> = nose rings/nose ornaments.</p>',
    "22": '<p>The catalog transitions to clothing: <strong>hammaḥălāṣôt</strong> = "holiday garments/festive robes" (from <em>ḥālaṣ</em> = to draw out, strip off — perhaps garments that were put on for festivals then removed); <strong>hammĕʿāṭāpôt</strong> = "capes/outer robes" (from <em>ʿāṭap̄</em> = to wrap, cover); <strong>hammiṭpāḥôt</strong> = "wraps/shawls"; <strong>haḥārīṭîm</strong> = "purses/bags" (possibly the reticulated bags or purses carried by women of status).</p>',
    "23": '<p><strong>haggîlyōnîm</strong> = "polished mirrors" (from <em>gālâ</em> = to uncover/reveal; mirrors that reveal appearance); <strong>hassĕdînîm</strong> = "linen garments/tunics" (fine linen underwear or outer garments); <strong>happenîpôt</strong> = "tiaras/turbans" (of a specific ceremonial type); <strong>harĕḏîdîm</strong> = "full-length veils/large wraps" (cf. Song 5:7). The exhaustive catalog concludes here — twenty-one items total, covering head to foot. The rhetorical effect is comprehensive: everything that adorned, defined, and signaled elite status is taken.</p>',
    "24": '<p><strong>wĕhāyâ taḥat-bōśem môqâ</strong> = "Instead of sweet perfume (<em>bōśem</em>), there will be a stench (<em>môqâ</em>)" — the four-fold <em>taḥat</em> ("instead of") refrain structures the reversals: perfume → stench; sash → rope; styled hair → shaved head; fine robe → sackcloth (with branded/scorched skin). <em>Taḥat</em> (under/instead of) is the word of covenant curse (Deut 28 uses it repeatedly for reversals of blessing into curse).</p><p><strong>kî taḥat yōpî</strong> = "for instead of beauty (<em>yōpî</em>)" — the final and climactic reversal: beauty itself, the thing the entire catalog describes, becomes something else. The MKT\'s "instead of fine robe, a garment of grief (<em>māḥăgōret śaq</em>)" and "burning instead of beauty" captures the complete overturning.</p>',
    "25": '<p><strong>mĕtayik bĕḥereḇ yippōlû</strong> = "Your men (<em>mĕtê</em>, pl. of <em>met</em> = mortal man) will fall by the sword (<em>ḥereḇ</em>)" — from adornment to battlefield. <em>Wĕgĕḇûrātēk</em> = "your warriors (<em>gĕḇûrâ</em> = strength/might, used for military prowess) in battle (<em>milḥāmâ</em>)." The military capacity that Judah trusted in (2:7: horses, chariots) will be destroyed in battle.</p>',
    "26": '<p><strong>wĕʾāněllû wĕʾāḇĕlû pĕtāḥeyhā</strong> = "And her city gates will mourn (<em>ʾānal</em>) and grieve (<em>ʾāḇal</em>)" — the personification of Jerusalem as a woman continues from 1:8 (bat-tsion); now the city gates (the places of commerce, judgment, and social life) mourn. <em>Pĕtāḥîm</em> = gate-openings. <strong>wĕnuqqĕtâ lāʾāreṣ tēšēḇ</strong> = "she will sit desolate (<em>nāqāh</em> = emptied, stripped) on the ground" — sitting on the ground is the posture of mourning (Job 2:13; Lam 2:10; Ezek 26:16). Jerusalem, stripped of its adornments (vv. 16-23) and its men (v. 25), sits in mourning on the ground.</p>'
  },
  "4": {
    "1": '<p><strong>wĕheḥĕzîqû šeḇaʿ nāšîm bĕʾîš ʾeḥāḏ</strong> = "And seven women will seize (<em>ḥāzaq</em>, to grasp firmly) one man" — the sequel to 3:25-26: so many men have died in battle that seven women compete for one surviving man. <em>Šeḇaʿ</em> (seven) is a round number signifying completion/totality — all the women; all the remaining men are overwhelmed by demand.</p><p><strong>leḥmēnû nōʾkal ûśimlātēnû nilbaš</strong> = "we will provide our own food (<em>leḥem</em>) and clothing (<em>simlâ</em>)" — in ANE marriage the husband provided food and clothing as fundamental obligations (cf. Exod 21:10). The women offer to waive these obligations — a sign of social desperation so extreme that the normal order of economic provision within marriage is abandoned. <strong>raq yiqqārēʾ šimmĕkā ʿālênû</strong> = "just let your name be called upon us" — to bear a man\'s name was to be under his protection and identity. The women seek identity and honor (<em>kherpa</em> = disgrace/reproach removed) even without the economic basis of marriage.</p>',
    "2": '<p><strong>ṣemaḥ YHWH</strong> = "the Branch of the LORD" — a title of the utmost Messianic importance. <em>Ṣemaḥ</em> (H6780) = a sprout, growth, shoot from a root. In this context it is theophoric: "the Shoot of YHWH" — not merely a branch of the Davidic line but one whose origin is attributed directly to YHWH himself. The parallel texts that deploy <em>ṣemaḥ</em> as a title are: Jer 23:5 ("I will raise up for David a righteous <em>ṣemaḥ</em>"); Jer 33:15 (same); Zech 3:8 ("my servant, the Branch"); Zech 6:12 ("Here is the man whose name is the Branch, and he will branch out from his place and build the temple"). In all these texts <em>ṣemaḥ</em> is clearly Messianic.</p><p><strong>liṣbî ûlĕkāḇôd wĕpĕrî hāʾāreṣ lĕgāʾôn ûlĕtipʾāret</strong> = "beautiful (<em>ṣĕḇî</em>) and glorious (<em>kāḇôd</em>), and the fruit of the earth will be the pride (<em>gāʾôn</em>) and splendor (<em>tipʾāret</em>) of those who survive Israel." The four positive words in this verse (beauty, glory, pride, splendor) are the exact reversal of the four-fold "instead of" in 3:24 (stench, rope, baldness, sackcloth). The Branch brings the reversal of judgment and the restoration of beauty.</p>',
    "3": '<p><strong>wĕhāyâ hannôṭār bĕṣiyyôn wĕhannôṭār bîrûšālāim qādôš yēʾāmer lô</strong> = "And whoever remains (<em>nôṭār</em>, niphal participle of <em>yātar</em> = to be left over, to remain) in Zion and whoever is left in Jerusalem will be called holy (<em>qādôš</em>) — everyone enrolled (<em>kātûḇ</em> = written/registered) among the living (<em>ḥayyîm</em>) in Jerusalem."</p><p>Two key terms: <em>śārîd</em> (remnant by survival) in 1:9 is now supplemented by <em>nôṭār</em> (remainder, survivor). More importantly: <strong>kātûḇ laḥayyîm</strong> = "written for/among the living" — this is the first clear reference in Isaiah to a heavenly register of the living (the "book of life" motif found in Exod 32:32-33; Ps 69:28; Dan 12:1; Mal 3:16-17; Rev 3:5; 13:8; 20:12). Enrollment in this register, not ethnic survival, defines the remnant as holy.</p>',
    "4": '<p><strong>ʾim-rāḥaṣ ʾăḏōnāy ʾet ṣōʾat bĕnôt ṣiyyôn</strong> = "when the Lord has washed away (<em>rāḥaṣ</em>) the filth (<em>ṣōʾâ</em> = excrement/filth) of the daughters of Zion" — the vocabulary of vv. 18-24 (adornment of the daughters) is reversed: the judgment that stripped the women (3:16-24) becomes the cleansing of filth. <em>Ṣōʾâ</em> is a deliberately coarse word for moral impurity — the filth is the moral equivalent of the physical waste that defiles.</p><p><strong>bĕrûaḥ mišpāṭ ûbĕrûaḥ bāʿēr</strong> = "by a spirit (<em>rûaḥ</em>) of judgment (<em>mišpāṭ</em>) and a spirit of burning/fire (<em>bāʿar</em>)." Two modes of divine cleansing: judicial (<em>mišpāṭ</em> — separating what belongs from what does not) and fiery refining (<em>bāʿar</em> — consuming the dross). The pairing anticipates the dual work of the Servant (purifying through justice) and the Spirit (baptism of fire — cf. Matt 3:11; Isa 44:3).</p>',
    "5": '<p><strong>wĕbārāʾ YHWH ʿal kol-mĕkôn har-ṣiyyôn</strong> = "Then the LORD will create (<em>bārāʾ</em>) over every dwelling-place on Mount Zion" — <em>bārāʾ</em> is the verb of divine creation from Genesis 1:1, reserved exclusively for divine creative acts with no human parallel. The new protective cloud over Zion is an act of creation in the same category as the original creation.</p><p><strong>ʿānān wĕʿāšān yômām ûnōgah ʾēš lĕhābâ lāylâ</strong> = "a cloud by day and smoke with the glow of flaming fire at night" — the Exodus theophany re-enacted. Cloud by day / fire by night is the specific mode of divine accompaniment in the wilderness (Exod 13:21-22; 40:38; Num 9:15-23). The eschatological Zion is not a return to pre-Exodus conditions but a new Exodus: YHWH re-inhabits his people with the visible presence that accompanied them from Egypt. <em>Kî ʿal-kol-kāḇôd ḥuppâ</em> = "for over all the glory there is a canopy (<em>ḥuppâ</em>)" — <em>ḥuppâ</em> = bridal canopy/wedding chamber; the image of YHWH\'s presence as a wedding canopy over his people is an extraordinary metaphor for covenant intimacy under divine protection.</p>',
    "6": '<p><strong>wĕsukkâ tihyeh lĕṣēl-yômām mēḥōreḇ</strong> = "There will be a shelter (<em>sukkâ</em>) for shade (<em>ṣēl</em>) from the heat (<em>ḥōreḇ</em>) of the day" — <em>sukkâ</em> here closes the frame opened in 1:8 (Jerusalem was "like a sukkah in a vineyard" — exposed and temporary). There the <em>sukkâ</em> was the image of vulnerability; here it is the image of divine protection. The same word, reversed in meaning: from the city exposed like a flimsy harvest booth to the eschatological community sheltered under a divine sukkah.</p><p><strong>ûlĕmisteir wĕlĕmaḥseh mizzærem ûmimmāṭār</strong> = "and a refuge (<em>mistār</em>) and hiding place (<em>māḥāseh</em>) from storm (<em>zérem</em>) and rain (<em>māṭār</em>)." The shelter from storm is both physical and eschatological. Three nouns for shelter in this verse (<em>sukkâ</em>, <em>mistār</em>, <em>māḥāseh</em>) answer the three images of Jerusalem\'s exposure in 1:8 (<em>sukkâ</em>, <em>mĕlûnâ</em>, <em>nĕṣûrâ</em>). The precision of the reversal is Isaiah\'s hallmark: the exact vocabulary of the indictment becomes the vocabulary of the promise.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-original', 'isaiah', existing)
    print('Isaiah 1-4 mkt-original written.')

if __name__ == '__main__':
    main()
